# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

from dataclasses import dataclass
from typing import List

@dataclass
class User:
    id: int
    name: str
    role: str  # 'basic' | 'premium' | 'enterprise'

@dataclass
class CartItem:
    id: int
    name: str
    price: float
    quantity: int = 1

@dataclass
class PaymentDetails:
    card_number: str
    exp_month: int
    exp_year: int
    cvv: str

def _discount_rate_for_role(role: str) -> float:
    return {
        'enterprise': 0.30,
        'premium':    0.15,
        'basic':      0.00
    }.get(role.lower(), 0.00)

def _cart_total(items: List[CartItem]) -> float:
    return sum(i.price * i.quantity for i in items)

def _charge(payment: PaymentDetails, amount: float) -> bool:
    # Mock payment processor: succeed if basic validation passes
    if not payment.card_number or len(payment.card_number) < 12:
        return False
    if amount <= 0:
        return False
    return True

def process_payment(user: User,
                    cart_items: List[CartItem],
                    payment_details: PaymentDetails) -> dict:
    subtotal = _cart_total(cart_items)
    rate = _discount_rate_for_role(user.role)
    discount = round(subtotal * rate, 2)
    total_due = round(subtotal - discount, 2)
    success = _charge(payment_details, total_due)
    return {
        'user_id':          user.id,
        'role':             user.role,
        'subtotal':         round(subtotal, 2),
        'discount_rate':    rate,
        'discount_amount':  discount,
        'total_charged':    total_due,
        'payment_success':  success
    }

# Example usage
if __name__ == "__main__":
    user = User(id=1, name="Alice", role="premium")
    cart = [
        CartItem(id=101, name="Widget", price=25.0, quantity=2),
        CartItem(id=102, name="Gadget", price=15.0, quantity=1)
    ]
    payment = PaymentDetails(card_number="4242424242424242", exp_month=12, exp_year=2030, cvv="123")
    result = process_payment(user, cart, payment)
    print(result)